class Solution:
    def countArrangement(self, n):
        used = [False] * (n + 1)
        def bt(pos):
            if pos > n:
                return 1
            c = 0
            for v in range(1, n + 1):
                if not used[v] and (v % pos == 0 or pos % v == 0):
                    used[v] = True
                    c += bt(pos + 1)
                    used[v] = False
            return c
        return bt(1)

