class Solution:
    def countArrangement(self, n):
        used = [False] * (n + 1)
        def dfs(pos):
            if pos == 0:
                return 1
            total = 0
            for v in range(1, n + 1):
                if not used[v] and (v % pos == 0 or pos % v == 0):
                    used[v] = True
                    total += dfs(pos - 1)
                    used[v] = False
            return total
        return dfs(n)

