var countArrangement = function(n) {
    const used = new Array(n + 1).fill(false);
    const dfs = (pos) => {
        if (pos === 0) return 1;
        let total = 0;
        for (let v = 1; v <= n; v++) {
            if (!used[v] && (v % pos === 0 || pos % v === 0)) {
                used[v] = true;
                total += dfs(pos - 1);
                used[v] = false;
            }
        }
        return total;
    };
    return dfs(n);
};
